mapper.select:
/* 팀 분류 조회 TeamCtgrDAO.list */ SELECT A.TEAM_TYCD , A.SBJCT_ID , A.ORG_ID , A.TEAM_CTGRNM , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_TEAM_CTGR A WHERE A.ORG_ID = #{orgId}
AND A.TEAM_TYCD = #{teamCtgrCd}
AND A.SBJCT_ID = #{crsCreCd}
AND LOWER(A.TEAM_CTGRNM) LIKE LOWER( '%' || #{teamCtgrNm} || '%')

/* 팀 분류 조회 TeamCtgrDAO.select */
SELECT CTGR.TEAM_TYCD , CTGR.SBJCT_ID , CTGR.ORG_ID , CTGR.TEAM_CTGRNM , CTGR.TEAM_BBS_YN , (SELECT COUNT(*) FROM TB_LMS_ASMT B WHERE B.TEAM_TYCD = CTGR.TEAM_TYCD) AS ASMNT_CNT , (SELECT COUNT(*) FROM TB_LMS_DSCS B WHERE B.TEAM_TYCD = CTGR.TEAM_TYCD) AS FORUM_CNT FROM TB_LMS_TEAM_CTGR CTGR WHERE 1=1
AND CTGR.SBJCT_ID = #{crsCreCd}
AND CTGR.TEAM_TYCD = #{teamCtgrCd}

/* 팀 분류 정보 TeamCtgrDAO.selecTeamForm */
SELECT CTGR.TEAM_TYCD , CTGR.SBJCT_ID , CTGR.ORG_ID , CTGR.TEAM_CTGRNM , CTGR.TEAM_BBS_YN FROM TB_LMS_TEAM_CTGR CTGR WHERE 1=1
AND CTGR.SBJCT_ID = #{crsCreCd}
AND CTGR.TEAM_TYCD = #{teamCtgrCd}

mapper.insert:
/*
	팀 분류 등록
	TeamCtgrDAO.insertTeamCtgr
*/
INSERT INTO TB_LMS_TEAM_CTGR (
	TEAM_TYCD
	, SBJCT_ID
	, ORG_ID
	, TEAM_CTGRNM
	, TEAM_BBS_YN
	, RGTR_ID
	, FRST_INQ_DTTM
) VALUES (
	#{teamCtgrCd}
	, #{crsCreCd}
	, #{orgId}
	, #{teamCtgrNm}
	, #{teamBbsYn}
	, #{rgtrId}
	, FN_DTTM()
)

/*
	팀 분류 수정
	TeamCtgrDAO.updateTeamCtgr
*/
UPDATE TB_LMS_TEAM_CTGR
SET MOD_DTTM = FN_DTTM()
	, MDFR_ID = #{mdfrId}

	, SBJCT_ID = #{crsCreCd}


	, ORG_ID = #{orgId}


	, TEAM_CTGRNM = #{teamCtgrNm}


	, TEAM_BBS_YN = #{teamBbsYn}

WHERE TEAM_TYCD = #{teamCtgrCd}

mapper.select:
/*
	팀 조회
	TeamCtgrDAO.selectTeam
*/
SELECT COUNT(*) FROM TEAM WHERE TEAM_TYCD = #{teamCtgrCd}

mapper.delete:
/*
	팀원 삭제
	TeamCtgrDAO.delTeamMember
*/
DELETE FROM TB_LMS_TEAM_MBR WHERE TEAM_ID IN (
	SELECT TEAM_ID FROM TEAM WHERE TEAM_TYCD = #{teamCtgrCd}
)

/*
	팀 삭제
	TeamCtgrDAO.delTeam
*/
DELETE FROM TEAM
WHERE TEAM_TYCD = #{teamCtgrCd}

/*
	팀분류 삭제
	TeamCtgrDAO.delete
*/
DELETE FROM TB_LMS_TEAM_CTGR
WHERE TEAM_TYCD = #{teamCtgrCd}

/*
	팀 수정시 팀원 삭제
	TeamCtgrDAO.editDelTeamMember
*/
DELETE FROM TB_LMS_TEAM_MBR WHERE TEAM_ID = #{teamCd}

mapper.select:
/*
	팀 분류 카운트
	TeamCtgrDAO.selectTeamCtgr
*/
SELECT COUNT(*) FROM TB_LMS_TEAM_CTGR WHERE TEAM_TYCD = #{teamCtgrCd}

mapper.update:
/*
	팀 구성 완료 여부 수정
	TeamCtgrDAO.setTeamSetYn
*/
UPDATE TB_LMS_TEAM_CTGR
	SET TEAM_CPST_CMPTNYN = #{teamSetYn}
WHERE SBJCT_ID = #{crsCreCd}
	AND TEAM_TYCD = #{teamCtgrCd}
